static void psy_3gpp_analyze_channel(FFPsyContext *ctx, int channel,

                                     const float *coefs, const FFPsyWindowInfo *wi)

{

    AacPsyContext *pctx = (AacPsyContext*) ctx->model_priv_data;

    AacPsyChannel *pch  = &pctx->ch[channel];

    int start = 0;

    int i, w, g;

    float desired_bits, desired_pe, delta_pe, reduction, spread_en[128] = {0};

    float a = 0.0f, active_lines = 0.0f, norm_fac = 0.0f;

    float pe = pctx->chan_bitrate > 32000 ? 0.0f : FFMAX(50.0f, 100.0f - pctx->chan_bitrate * 100.0f / 32000.0f);

    const int      num_bands   = ctx->num_bands[wi->num_windows == 8];

    const uint8_t *band_sizes  = ctx->bands[wi->num_windows == 8];

    AacPsyCoeffs  *coeffs      = pctx->psy_coef[wi->num_windows == 8];

    const float avoid_hole_thr = wi->num_windows == 8 ? PSY_3GPP_AH_THR_SHORT : PSY_3GPP_AH_THR_LONG;



    //calculate energies, initial thresholds and related values - 5.4.2 "Threshold Calculation"

    for (w = 0; w < wi->num_windows*16; w += 16) {

        for (g = 0; g < num_bands; g++) {

            AacPsyBand *band = &pch->band[w+g];



            float form_factor = 0.0f;

            band->energy = 0.0f;

            for (i = 0; i < band_sizes[g]; i++) {

                band->energy += coefs[start+i] * coefs[start+i];

                form_factor  += sqrtf(fabs(coefs[start+i]));

            }

            band->thr      = band->energy * 0.001258925f;

            band->nz_lines = form_factor / powf(band->energy / band_sizes[g], 0.25f);



            start += band_sizes[g];

        }

    }

    //modify thresholds and energies - spread, threshold in quiet, pre-echo control

    for (w = 0; w < wi->num_windows*16; w += 16) {

        AacPsyBand *bands = &pch->band[w];



        //5.4.2.3 "Spreading" & 5.4.3 "Spreaded Energy Calculation"

        spread_en[0] = bands[0].energy;

        for (g = 1; g < num_bands; g++) {

            bands[g].thr   = FFMAX(bands[g].thr,    bands[g-1].thr * coeffs[g].spread_hi[0]);

            spread_en[w+g] = FFMAX(bands[g].energy, spread_en[w+g-1] * coeffs[g].spread_hi[1]);

        }

        for (g = num_bands - 2; g >= 0; g--) {

            bands[g].thr   = FFMAX(bands[g].thr,   bands[g+1].thr * coeffs[g].spread_low[0]);

            spread_en[w+g] = FFMAX(spread_en[w+g], spread_en[w+g+1] * coeffs[g].spread_low[1]);

        }

        //5.4.2.4 "Threshold in quiet"

        for (g = 0; g < num_bands; g++) {

            AacPsyBand *band = &bands[g];



            band->thr_quiet = band->thr = FFMAX(band->thr, coeffs[g].ath);

            //5.4.2.5 "Pre-echo control"

            if (!(wi->window_type[0] == LONG_STOP_SEQUENCE || (wi->window_type[1] == LONG_START_SEQUENCE && !w)))

                band->thr = FFMAX(PSY_3GPP_RPEMIN*band->thr, FFMIN(band->thr,

                                  PSY_3GPP_RPELEV*pch->prev_band[w+g].thr_quiet));



            /* 5.6.1.3.1 "Prepatory steps of the perceptual entropy calculation" */

            pe += calc_pe_3gpp(band);

            a  += band->pe_const;

            active_lines += band->active_lines;



            /* 5.6.1.3.3 "Selection of the bands for avoidance of holes" */

            if (spread_en[w+g] * avoid_hole_thr > band->energy || coeffs[g].min_snr > 1.0f)

                band->avoid_holes = PSY_3GPP_AH_NONE;

            else

                band->avoid_holes = PSY_3GPP_AH_INACTIVE;

        }

    }



    /* 5.6.1.3.2 "Calculation of the desired perceptual entropy" */

    ctx->ch[channel].entropy = pe;

    desired_bits = calc_bit_demand(pctx, pe, ctx->bitres.bits, ctx->bitres.size, wi->num_windows == 8);

    desired_pe = PSY_3GPP_BITS_TO_PE(desired_bits);

    /* NOTE: PE correction is kept simple. During initial testing it had very

     *       little effect on the final bitrate. Probably a good idea to come

     *       back and do more testing later.

     */

    if (ctx->bitres.bits > 0)

        desired_pe *= av_clipf(pctx->pe.previous / PSY_3GPP_BITS_TO_PE(ctx->bitres.bits),

                               0.85f, 1.15f);

    pctx->pe.previous = PSY_3GPP_BITS_TO_PE(desired_bits);



    if (desired_pe < pe) {

        /* 5.6.1.3.4 "First Estimation of the reduction value" */

        for (w = 0; w < wi->num_windows*16; w += 16) {

            reduction = calc_reduction_3gpp(a, desired_pe, pe, active_lines);

            pe = 0.0f;

            a  = 0.0f;

            active_lines = 0.0f;

            for (g = 0; g < num_bands; g++) {

                AacPsyBand *band = &pch->band[w+g];



                band->thr = calc_reduced_thr_3gpp(band, coeffs[g].min_snr, reduction);

                /* recalculate PE */

                pe += calc_pe_3gpp(band);

                a  += band->pe_const;

                active_lines += band->active_lines;

            }

        }



        /* 5.6.1.3.5 "Second Estimation of the reduction value" */

        for (i = 0; i < 2; i++) {

            float pe_no_ah = 0.0f, desired_pe_no_ah;

            active_lines = a = 0.0f;

            for (w = 0; w < wi->num_windows*16; w += 16) {

                for (g = 0; g < num_bands; g++) {

                    AacPsyBand *band = &pch->band[w+g];



                    if (band->avoid_holes != PSY_3GPP_AH_ACTIVE) {

                        pe_no_ah += band->pe;

                        a        += band->pe_const;

                        active_lines += band->active_lines;

                    }

                }

            }

            desired_pe_no_ah = FFMAX(desired_pe - (pe - pe_no_ah), 0.0f);

            if (active_lines > 0.0f)

                reduction += calc_reduction_3gpp(a, desired_pe_no_ah, pe_no_ah, active_lines);



            pe = 0.0f;

            for (w = 0; w < wi->num_windows*16; w += 16) {

                for (g = 0; g < num_bands; g++) {

                    AacPsyBand *band = &pch->band[w+g];



                    if (active_lines > 0.0f)

                        band->thr = calc_reduced_thr_3gpp(band, coeffs[g].min_snr, reduction);

                    pe += calc_pe_3gpp(band);

                    band->norm_fac = band->active_lines / band->thr;

                    norm_fac += band->norm_fac;

                }

            }

            delta_pe = desired_pe - pe;

            if (fabs(delta_pe) > 0.05f * desired_pe)

                break;

        }



        if (pe < 1.15f * desired_pe) {

            /* 6.6.1.3.6 "Final threshold modification by linearization" */

            norm_fac = 1.0f / norm_fac;

            for (w = 0; w < wi->num_windows*16; w += 16) {

                for (g = 0; g < num_bands; g++) {

                    AacPsyBand *band = &pch->band[w+g];



                    if (band->active_lines > 0.5f) {

                        float delta_sfb_pe = band->norm_fac * norm_fac * delta_pe;

                        float thr = band->thr;



                        thr *= powf(2.0f, delta_sfb_pe / band->active_lines);

                        if (thr > coeffs[g].min_snr * band->energy && band->avoid_holes == PSY_3GPP_AH_INACTIVE)

                            thr = FFMAX(band->thr, coeffs[g].min_snr * band->energy);

                        band->thr = thr;

                    }

                }

            }

        } else {

            /* 5.6.1.3.7 "Further perceptual entropy reduction" */

            g = num_bands;

            while (pe > desired_pe && g--) {

                for (w = 0; w < wi->num_windows*16; w+= 16) {

                    AacPsyBand *band = &pch->band[w+g];

                    if (band->avoid_holes != PSY_3GPP_AH_NONE && coeffs[g].min_snr < PSY_SNR_1DB) {

                        coeffs[g].min_snr = PSY_SNR_1DB;

                        band->thr = band->energy * PSY_SNR_1DB;

                        pe += band->active_lines * 1.5f - band->pe;

                    }

                }

            }

            /* TODO: allow more holes (unused without mid/side) */

        }

    }



    for (w = 0; w < wi->num_windows*16; w += 16) {

        for (g = 0; g < num_bands; g++) {

            AacPsyBand *band     = &pch->band[w+g];

            FFPsyBand  *psy_band = &ctx->ch[channel].psy_bands[w+g];



            psy_band->threshold = band->thr;

            psy_band->energy    = band->energy;

        }

    }



    memcpy(pch->prev_band, pch->band, sizeof(pch->band));

}

static inline int qemu_rdma_buffer_mergable(RDMAContext *rdma,

                    uint64_t offset, uint64_t len)

{

    RDMALocalBlock *block =

        &(rdma->local_ram_blocks.block[rdma->current_index]);

    uint8_t *host_addr = block->local_host_addr + (offset - block->offset);

    uint8_t *chunk_end = ram_chunk_end(block, rdma->current_chunk);



    if (rdma->current_length == 0) {

        return 0;

    }



    /*

     * Only merge into chunk sequentially.

     */

    if (offset != (rdma->current_addr + rdma->current_length)) {

        return 0;

    }



    if (rdma->current_index < 0) {

        return 0;

    }



    if (offset < block->offset) {

        return 0;

    }



    if ((offset + len) > (block->offset + block->length)) {

        return 0;

    }



    if (rdma->current_chunk < 0) {

        return 0;

    }



    if ((host_addr + len) > chunk_end) {

        return 0;

    }



    return 1;

}

static int build_vlc(AVCodecContext *avctx, VLC *vlc, const uint32_t *table)

{

    Node nodes[512];

    uint32_t bits[256];

    int16_t lens[256];

    uint8_t xlat[256];

    int cur_node, i, j, pos = 0;



    ff_free_vlc(vlc);



    for (i = 0; i < 256; i++) {

        nodes[i].count = table[i];

        nodes[i].sym   = i;

        nodes[i].n0    = -2;

        nodes[i].l     = i;

        nodes[i].r     = i;

    }



    cur_node = 256;

    j = 0;

    do {

        for (i = 0; ; i++) {

            int new_node = j;

            int first_node = cur_node;

            int second_node = cur_node;

            int nd, st;



            nodes[cur_node].count = -1;



            do {

                int val = nodes[new_node].count;

                if (val && (val < nodes[first_node].count)) {

                    if (val >= nodes[second_node].count) {

                        first_node = new_node;

                    } else {

                        first_node = second_node;

                        second_node = new_node;

                    }

                }

                new_node += 1;

            } while (new_node != cur_node);



            if (first_node == cur_node)

                break;



            nd = nodes[second_node].count;

            st = nodes[first_node].count;

            nodes[second_node].count = 0;

            nodes[first_node].count  = 0;

            nodes[cur_node].count = nd + st;

            nodes[cur_node].sym = -1;

            nodes[cur_node].n0 = cur_node;

            nodes[cur_node].l = first_node;

            nodes[cur_node].r = second_node;

            cur_node++;

        }

        j++;

    } while (cur_node - 256 == j);



    get_tree_codes(bits, lens, xlat, nodes, cur_node - 1, 0, 0, &pos);



    return ff_init_vlc_sparse(vlc, 10, pos, lens, 2, 2, bits, 4, 4, xlat, 1, 1, 0);

}

static int vb_decode_framedata(VBDecContext *c, const uint8_t *buf, int offset)

{

    uint8_t *prev, *cur;

    int blk, blocks, t, blk2;

    int blocktypes = 0;

    int x, y, a, b;

    int pattype, pattern;

    const int width = c->avctx->width;

    uint8_t *pstart = c->prev_frame;

    uint8_t *pend = c->prev_frame + width*c->avctx->height;



    prev = c->prev_frame + offset;

    cur = c->frame;



    blocks = (c->avctx->width >> 2) * (c->avctx->height >> 2);

    blk2 = 0;

    for(blk = 0; blk < blocks; blk++){

        if(!(blk & 3))

            blocktypes = bytestream_get_byte(&buf);

        switch(blocktypes & 0xC0){

        case 0x00: //skip

            for(y = 0; y < 4; y++)

                if(check_line(prev + y*width, pstart, pend))

                    memcpy(cur + y*width, prev + y*width, 4);

                else

                    memset(cur + y*width, 0, 4);

            break;

        case 0x40:

            t = bytestream_get_byte(&buf);

            if(!t){ //raw block

                for(y = 0; y < 4; y++)

                    memcpy(cur + y*width, buf + y*4, 4);

                buf += 16;

            }else{ // motion compensation

                x = ((t & 0xF)^8) - 8;

                y = ((t >> 4) ^8) - 8;

                t = x + y*width;

                for(y = 0; y < 4; y++)

                    if(check_line(prev + t + y*width, pstart, pend))

                        memcpy(cur + y*width, prev + t + y*width, 4);

                    else

                        memset(cur + y*width, 0, 4);

            }

            break;

        case 0x80: // fill

            t = bytestream_get_byte(&buf);

            for(y = 0; y < 4; y++)

                memset(cur + y*width, t, 4);

            break;

        case 0xC0: // pattern fill

            t = bytestream_get_byte(&buf);

            pattype = t >> 6;

            pattern = vb_patterns[t & 0x3F];

            switch(pattype){

            case 0:

                a = bytestream_get_byte(&buf);

                b = bytestream_get_byte(&buf);

                for(y = 0; y < 4; y++)

                    for(x = 0; x < 4; x++, pattern >>= 1)

                        cur[x + y*width] = (pattern & 1) ? b : a;

                break;

            case 1:

                pattern = ~pattern;

            case 2:

                a = bytestream_get_byte(&buf);

                for(y = 0; y < 4; y++)

                    for(x = 0; x < 4; x++, pattern >>= 1)

                        if(pattern & 1 && check_pixel(prev + x + y*width, pstart, pend))

                            cur[x + y*width] = prev[x + y*width];

                        else

                            cur[x + y*width] = a;

                break;

            case 3:

                av_log(c->avctx, AV_LOG_ERROR, "Invalid opcode seen @%d\n",blk);

                return -1;

            }

            break;

        }

        blocktypes <<= 2;

        cur  += 4;

        prev += 4;

        blk2++;

        if(blk2 == (width >> 2)){

            blk2 = 0;

            cur  += width * 3;

            prev += width * 3;

        }

    }

    return 0;

}

sd_co_get_block_status(BlockDriverState *bs, int64_t sector_num, int nb_sectors,

                       int *pnum)

{

    BDRVSheepdogState *s = bs->opaque;

    SheepdogInode *inode = &s->inode;

    uint32_t object_size = (UINT32_C(1) << inode->block_size_shift);

    uint64_t offset = sector_num * BDRV_SECTOR_SIZE;

    unsigned long start = offset / object_size,

                  end = DIV_ROUND_UP((sector_num + nb_sectors) *

                                     BDRV_SECTOR_SIZE, object_size);

    unsigned long idx;

    int64_t ret = BDRV_BLOCK_DATA | BDRV_BLOCK_OFFSET_VALID | offset;



    for (idx = start; idx < end; idx++) {

        if (inode->data_vdi_id[idx] == 0) {

            break;

        }

    }

    if (idx == start) {

        /* Get the longest length of unallocated sectors */

        ret = 0;

        for (idx = start + 1; idx < end; idx++) {

            if (inode->data_vdi_id[idx] != 0) {

                break;

            }

        }

    }



    *pnum = (idx - start) * object_size / BDRV_SECTOR_SIZE;

    if (*pnum > nb_sectors) {

        *pnum = nb_sectors;

    }

    return ret;

}

static int handle_secondary_tcp_pkt(NetFilterState *nf,

                                    Connection *conn,

                                    Packet *pkt)

{

    struct tcphdr *tcp_pkt;



    tcp_pkt = (struct tcphdr *)pkt->transport_header;



    if (trace_event_get_state(TRACE_COLO_FILTER_REWRITER_DEBUG)) {

        trace_colo_filter_rewriter_pkt_info(__func__,

                    inet_ntoa(pkt->ip->ip_src), inet_ntoa(pkt->ip->ip_dst),

                    ntohl(tcp_pkt->th_seq), ntohl(tcp_pkt->th_ack),

                    tcp_pkt->th_flags);

        trace_colo_filter_rewriter_conn_offset(conn->offset);

    }



    if (((tcp_pkt->th_flags & (TH_ACK | TH_SYN)) == (TH_ACK | TH_SYN))) {

        /*

         * save offset = secondary_seq and then

         * in handle_primary_tcp_pkt make offset

         * = secondary_seq - primary_seq

         */

        conn->offset = ntohl(tcp_pkt->th_seq);

    }



    if ((tcp_pkt->th_flags & (TH_ACK | TH_SYN)) == TH_ACK) {

        /* handle packets to the primary from the secondary*/

        tcp_pkt->th_seq = htonl(ntohl(tcp_pkt->th_seq) - conn->offset);



        net_checksum_calculate((uint8_t *)pkt->data, pkt->size);

    }



    return 0;

}

static int qemu_rdma_put_buffer(void *opaque, const uint8_t *buf,

                                int64_t pos, int size)

{

    QEMUFileRDMA *r = opaque;

    QEMUFile *f = r->file;

    RDMAContext *rdma = r->rdma;

    size_t remaining = size;

    uint8_t * data = (void *) buf;

    int ret;



    CHECK_ERROR_STATE();



    /*

     * Push out any writes that

     * we're queued up for VM's ram.

     */

    ret = qemu_rdma_write_flush(f, rdma);

    if (ret < 0) {

        rdma->error_state = ret;

        return ret;

    }



    while (remaining) {

        RDMAControlHeader head;



        r->len = MIN(remaining, RDMA_SEND_INCREMENT);

        remaining -= r->len;



        head.len = r->len;

        head.type = RDMA_CONTROL_QEMU_FILE;



        ret = qemu_rdma_exchange_send(rdma, &head, data, NULL, NULL, NULL);



        if (ret < 0) {

            rdma->error_state = ret;

            return ret;

        }



        data += r->len;

    }



    return size;

}

static inline void helper_ret_protected(int shift, int is_iret, int addend)

{

    uint32_t sp, new_cs, new_eip, new_eflags, new_esp, new_ss;

    uint32_t new_es, new_ds, new_fs, new_gs;

    uint32_t e1, e2, ss_e1, ss_e2;

    int cpl, dpl, rpl, eflags_mask;

    uint8_t *ssp;



    sp = ESP;

    if (!(env->segs[R_SS].flags & DESC_B_MASK))

        sp &= 0xffff;

    ssp = env->segs[R_SS].base + sp;

    if (shift == 1) {

        /* 32 bits */

        if (is_iret)

            new_eflags = ldl_kernel(ssp + 8);

        new_cs = ldl_kernel(ssp + 4) & 0xffff;

        new_eip = ldl_kernel(ssp);

        if (is_iret && (new_eflags & VM_MASK))

            goto return_to_vm86;

    } else {

        /* 16 bits */

        if (is_iret)

            new_eflags = lduw_kernel(ssp + 4);

        new_cs = lduw_kernel(ssp + 2);

        new_eip = lduw_kernel(ssp);

    }

    if ((new_cs & 0xfffc) == 0)

        raise_exception_err(EXCP0D_GPF, new_cs & 0xfffc);

    if (load_segment(&e1, &e2, new_cs) != 0)

        raise_exception_err(EXCP0D_GPF, new_cs & 0xfffc);

    if (!(e2 & DESC_S_MASK) ||

        !(e2 & DESC_CS_MASK))

        raise_exception_err(EXCP0D_GPF, new_cs & 0xfffc);

    cpl = env->hflags & HF_CPL_MASK;

    rpl = new_cs & 3; 

    if (rpl < cpl)

        raise_exception_err(EXCP0D_GPF, new_cs & 0xfffc);

    dpl = (e2 >> DESC_DPL_SHIFT) & 3;

    if (e2 & DESC_CS_MASK) {

        if (dpl > rpl)

            raise_exception_err(EXCP0D_GPF, new_cs & 0xfffc);

    } else {

        if (dpl != rpl)

            raise_exception_err(EXCP0D_GPF, new_cs & 0xfffc);

    }

    if (!(e2 & DESC_P_MASK))

        raise_exception_err(EXCP0B_NOSEG, new_cs & 0xfffc);



    if (rpl == cpl) {

        /* return to same priledge level */

        cpu_x86_load_seg_cache(env, R_CS, new_cs, 

                       get_seg_base(e1, e2),

                       get_seg_limit(e1, e2),

                       e2);

        new_esp = sp + (4 << shift) + ((2 * is_iret) << shift) + addend;

    } else {

        /* return to different priviledge level */

        ssp += (4 << shift) + ((2 * is_iret) << shift) + addend;

        if (shift == 1) {

            /* 32 bits */

            new_esp = ldl_kernel(ssp);

            new_ss = ldl_kernel(ssp + 4) & 0xffff;

        } else {

            /* 16 bits */

            new_esp = lduw_kernel(ssp);

            new_ss = lduw_kernel(ssp + 2);

        }



        if ((new_ss & 3) != rpl)

            raise_exception_err(EXCP0D_GPF, new_ss & 0xfffc);

        if (load_segment(&ss_e1, &ss_e2, new_ss) != 0)

            raise_exception_err(EXCP0D_GPF, new_ss & 0xfffc);

        if (!(ss_e2 & DESC_S_MASK) ||

            (ss_e2 & DESC_CS_MASK) ||

            !(ss_e2 & DESC_W_MASK))

            raise_exception_err(EXCP0D_GPF, new_ss & 0xfffc);

        dpl = (ss_e2 >> DESC_DPL_SHIFT) & 3;

        if (dpl != rpl)

            raise_exception_err(EXCP0D_GPF, new_ss & 0xfffc);

        if (!(ss_e2 & DESC_P_MASK))

            raise_exception_err(EXCP0B_NOSEG, new_ss & 0xfffc);



        cpu_x86_load_seg_cache(env, R_CS, new_cs, 

                       get_seg_base(e1, e2),

                       get_seg_limit(e1, e2),

                       e2);

        cpu_x86_load_seg_cache(env, R_SS, new_ss, 

                       get_seg_base(ss_e1, ss_e2),

                       get_seg_limit(ss_e1, ss_e2),

                       ss_e2);

        cpu_x86_set_cpl(env, rpl);

    }

    if (env->segs[R_SS].flags & DESC_B_MASK)

        ESP = new_esp;

    else

        ESP = (ESP & 0xffff0000) | 

            (new_esp & 0xffff);

    env->eip = new_eip;

    if (is_iret) {

        /* NOTE: 'cpl' can be different from the current CPL */

        if (cpl == 0)

            eflags_mask = FL_UPDATE_CPL0_MASK;

        else

            eflags_mask = FL_UPDATE_MASK32;

        if (shift == 0)

            eflags_mask &= 0xffff;

        load_eflags(new_eflags, eflags_mask);

    }

    return;



 return_to_vm86:

    new_esp = ldl_kernel(ssp + 12);

    new_ss = ldl_kernel(ssp + 16);

    new_es = ldl_kernel(ssp + 20);

    new_ds = ldl_kernel(ssp + 24);

    new_fs = ldl_kernel(ssp + 28);

    new_gs = ldl_kernel(ssp + 32);



    /* modify processor state */

    load_eflags(new_eflags, FL_UPDATE_CPL0_MASK | VM_MASK | VIF_MASK | VIP_MASK);

    load_seg_vm(R_CS, new_cs);

    cpu_x86_set_cpl(env, 3);

    load_seg_vm(R_SS, new_ss);

    load_seg_vm(R_ES, new_es);

    load_seg_vm(R_DS, new_ds);

    load_seg_vm(R_FS, new_fs);

    load_seg_vm(R_GS, new_gs);



    env->eip = new_eip;

    ESP = new_esp;

}

