static int is_not_zero(const uint8_t *sector, int len)

{

    /*

     * Use long as the biggest available internal data type that fits into the

     * CPU register and unroll the loop to smooth out the effect of memory

     * latency.

     */



    int i;

    long d0, d1, d2, d3;

    const long * const data = (const long *) sector;



    len /= sizeof(long);



    for(i = 0; i < len; i += 4) {

        d0 = data[i + 0];

        d1 = data[i + 1];

        d2 = data[i + 2];

        d3 = data[i + 3];



        if (d0 || d1 || d2 || d3) {

            return 1;

        }

    }



    return 0;

}

static int unix_open(URLContext *h, const char *filename, int flags)

{

    UnixContext *s = h->priv_data;

    int fd, ret;



    av_strstart(filename, "unix:", &filename);

    s->addr.sun_family = AF_UNIX;

    av_strlcpy(s->addr.sun_path, filename, sizeof(s->addr.sun_path));



    if ((fd = ff_socket(AF_UNIX, s->type, 0)) < 0)

        return ff_neterrno();



    if (s->listen) {

        fd = ff_listen_bind(fd, (struct sockaddr *)&s->addr,

                            sizeof(s->addr), s->timeout, h);

        if (fd < 0) {

            ret = fd;

            goto fail;

        }

    } else {

        ret = ff_listen_connect(fd, (struct sockaddr *)&s->addr,

                                sizeof(s->addr), s->timeout, h, 0);

        if (ret < 0)

            goto fail;

    }



    s->fd = fd;



    return 0;



fail:

    if (s->listen && AVUNERROR(ret) != EADDRINUSE)

        unlink(s->addr.sun_path);

    if (fd >= 0)

        closesocket(fd);

    return ret;

}

int target_get_monitor_def(CPUState *cs, const char *name, uint64_t *pval)

{

    int i, regnum;

    PowerPCCPU *cpu = POWERPC_CPU(cs);

    CPUPPCState *env = &cpu->env;



    /* General purpose registers */

    if ((tolower(name[0]) == 'r') &&

        ppc_cpu_get_reg_num(name + 1, ARRAY_SIZE(env->gpr), &regnum)) {

        *pval = env->gpr[regnum];

        return 0;

    }



    /* Floating point registers */

    if ((tolower(name[0]) == 'f') &&

        ppc_cpu_get_reg_num(name + 1, ARRAY_SIZE(env->fpr), &regnum)) {

        *pval = env->fpr[regnum];

        return 0;

    }



    /* Special purpose registers */

    for (i = 0; i < ARRAY_SIZE(env->spr_cb); ++i) {

        ppc_spr_t *spr = &env->spr_cb[i];



        if (spr->name && (strcasecmp(name, spr->name) == 0)) {

            *pval = env->spr[i];

            return 0;

        }

    }



    /* Segment registers */

#if !defined(CONFIG_USER_ONLY)

    if ((strncasecmp(name, "sr", 2) == 0) &&

        ppc_cpu_get_reg_num(name + 2, ARRAY_SIZE(env->sr), &regnum)) {

        *pval = env->sr[regnum];

        return 0;

    }

#endif



    return -EINVAL;

}

